from flask import Flask, request, jsonify
import logging
import logging.handlers
import os

app = Flask(__name__)

LOG_FILE = 'application.log'
LOG_LEVEL = logging.INFO

# Ensure log directory exists
os.makedirs(os.path.dirname(LOG_FILE), exist_ok=True)

# Configure logging
logger = logging.getLogger('WebAppLogger')
logger.setLevel(LOG_LEVEL)
handler = logging.handlers.RotatingFileHandler(LOG_FILE, maxBytes=10485760, backupCount=5)
formatter = logging.Formatter('%(asctime)s - %(levelname)s - %(message)s')
handler.setFormatter(formatter)
logger.addHandler(handler)

@app.route('/log', methods=['POST'])
def log_message():
    try:
        data = request.get_json()
        if not data or 'message' not in data or 'level' not in data:
            return jsonify({'error': 'Invalid request'}), 400

        message = str(data['message'])
        level = str(data['level']).upper()

        if level not in ['DEBUG', 'INFO', 'WARNING', 'ERROR', 'CRITICAL']:
            return jsonify({'error': 'Invalid log level'}), 400

        log_func = getattr(logger, level.lower(), None)
        if callable(log_func):
            log_func(message)
            return jsonify({'status': 'Logged successfully'}), 200
        else:
            return jsonify({'error': 'Logging function not found'}), 500
    except Exception as e:
        logger.error('Exception occurred: %s', e)
        return jsonify({'error': 'Internal server error'}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)